import { GoogleGenAI, Type } from "@google/genai";
import { ParsedBill, VisionResult } from "../types";

const SYSTEM_INSTRUCTION_V2 = `
# ROLE: Indian Kirana Accountant
Analyze the message strictly from a financial/accounting perspective.

# SLANG DICTIONARY
- "Likh lo", "Udhari", "Dena hai", item-only messages (e.g. "5kg chawal")
  → INTENT: NEW_BILL (CREDIT)

- "Jama kiye", "Pay kiya", "GPay", "PhonePe", "Kat lo", "Hisaab clear", "Diya"
  → INTENT: PAYMENT_RECEIVED (DEBIT)

- "Bhaiya", "Ok", "👍", "Rate kya", "Dukaan khuli?", "Thanks"
  → INTENT: SKIP

# RULES
1) Ignore non-financial messages (intent = SKIP)
2) If message contains "Number + Item", assume NEW_BILL by default
3) Convert shorthand amounts:
   - 5k = 5000
   - 10k = 10000
4) If ITEM or ACTION word missing, set confidence = 0.5
5) Slang Normalization: Dudh/Milk -> "Dairy", Sabji/Vegetables -> "Vegetables".

# OUTPUT JSON
{
  "intent": "NEW_BILL" | "PAYMENT_RECEIVED" | "SKIP",
  "amount": Number,
  "items": "String description of items",
  "customer_name": "String or 'Customer'",
  "confidence": 0.0-1.0
}

Constraint: Return STRICT valid JSON only. No conversational filler.
`;

const VISION_INSTRUCTION = `
Role: Enterprise OCR Specialist
Task: Extract transaction details from photos of handwritten or printed Kirana bills.
Identify:
1. detected_text: Raw OCR transcription.
2. amount: Total sum.
3. items: Array of strings.

Return STRICT JSON only.
`;

const PLATFORM_EXPERT_INSTRUCTION = `
You are the DukaanMitra Platform Expert, a senior consultant helping founders build and scale their WhatsApp-based Kirana ledger system.
Your knowledge includes:
- System Architecture: Gupshup -> Make.com -> Google Sheets/PostgreSQL -> Razorpay.
- Operational Playbooks: Field sales, pilot onboarding, EOD reporting.
- Scaling: Migrating to SQL, Vision OCR using Gemini, and SaaS multi-tenancy.
- Day 6 Optimization: Pre-AI garbage filters, Desi Slang Dictionary, and Confidence Loops.
- Legal: India DPDP Act 2025 compliance.

Answer questions clearly and professionally. Use thinking mode to reason through complex deployment or architectural queries. Provide code snippets or sheet formulas when helpful.
`;

export const parseMessage = async (text: string): Promise<ParsedBill> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: text,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION_V2,
        temperature: 0.1,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            customer_name: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            items: { type: Type.STRING },
            intent: { type: Type.STRING, description: "NEW_BILL, PAYMENT_RECEIVED, or SKIP" },
            confidence: { type: Type.NUMBER }
          },
          required: ["customer_name", "amount", "items", "intent", "confidence"]
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Parsing Error:", error);
    return {
      customer_name: "Error",
      amount: 0,
      items: "Failed to parse",
      intent: 'SKIP',
      confidence: 0
    };
  }
};

export const parseImageBill = async (base64Image: string): Promise<VisionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          inlineData: {
            mimeType: "image/jpeg",
            data: base64Image
          }
        },
        { text: "Extract bill details as JSON." }
      ],
      config: {
        systemInstruction: VISION_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            detected_text: { type: Type.STRING },
            mapped_data: {
              type: Type.OBJECT,
              properties: {
                amount: { type: Type.NUMBER },
                items: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["amount", "items"]
            },
            confidence: { type: Type.NUMBER }
          },
          required: ["detected_text", "mapped_data", "confidence"]
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Vision Error:", error);
    return {
      detected_text: "Vision processing failed",
      mapped_data: { amount: 0, items: [] },
      confidence: 0
    };
  }
};

export const generateChatResponse = async (prompt: string, history: any[] = []): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [
        ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: PLATFORM_EXPERT_INSTRUCTION,
        thinkingConfig: { thinkingBudget: 32768 }
      }
    });

    return response.text || "I'm sorry, I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "The system is currently experiencing issues. Please try again later.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { parseMessage, parseImageBill } from '../services/geminiService';
import { Customer, Transaction, SystemLog } from '../types';

interface SimulatorProps {
  customers: Customer[];
  setCustomers: React.Dispatch<React.SetStateAction<Customer[]>>;
  transactions: Transaction[];
  setTransactions: React.Dispatch<React.SetStateAction<Transaction[]>>;
  logs: SystemLog[];
  setLogs: React.Dispatch<React.SetStateAction<SystemLog[]>>;
}

const Simulator: React.FC<SimulatorProps> = ({ 
  customers, setCustomers, 
  transactions, setTransactions, 
  logs, setLogs 
}) => {
  const [message, setMessage] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeRoute, setActiveRoute] = useState<string | null>(null);
  const [costSaved, setCostSaved] = useState(0);
  const [aiRequests, setAiRequests] = useState(0);
  const [chatHistory, setChatHistory] = useState<{ sender: 'user' | 'bot'; text: string; isImage?: boolean; isDoc?: boolean }[]>([
    { sender: 'bot', text: "Namaste! Optimization Engine Active. 🧠\nTry sending 'Ok' or 'Thanks' to test the Chai-Sutta Filter!" }
  ]);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [chatHistory]);

  const handleSendMessage = async () => {
    if (!message.trim() || isProcessing) return;

    const userMsg = message.trim();
    setMessage("");
    setChatHistory(prev => [...prev, { sender: 'user', text: userMsg }]);
    setIsProcessing(true);
    setActiveRoute(null);

    const mockUserPhone = "919876543210"; 
    const existingUser = customers.find(c => c.phone === mockUserPhone);
    const lowerMsg = userMsg.toLowerCase();

    // --- DAY 6: CHAI-SUTTA FILTER ---
    const garbageKeywords = ['ok', 'okay', 'thanks', 'thank you', 'theek', 'accha', '👍'];
    const isGarbage = garbageKeywords.some(kw => lowerMsg.includes(kw)) || userMsg.length <= 3;

    if (isGarbage) {
      setActiveRoute("CHAI_SUTTA_FILTER");
      setCostSaved(prev => prev + 1);
      await new Promise(res => setTimeout(res, 500));
      // In a real system, the scenario just STOPS. In simulator, we show the filter hit.
      setChatHistory(prev => [...prev, { 
        sender: 'bot', 
        text: "Day6_Filter: Garbage input detected. Request blocked. Cost saved! ☕" 
      }]);
      setIsProcessing(false);
      return;
    }

    // --- DAY 2-5: INQUIRY LANE ---
    if (lowerMsg.startsWith("pdf") || lowerMsg.includes("hisaab") || lowerMsg.includes("balance") || lowerMsg.includes("kitna") || lowerMsg.includes("total")) {
      setActiveRoute("INQUIRY_LANE");
      setChatHistory(prev => [...prev, { sender: 'bot', text: `Fetching records for +${mockUserPhone}...` }]);
      await new Promise(res => setTimeout(res, 1000));

      if (lowerMsg.startsWith("pdf")) {
        setChatHistory(prev => [...prev, { sender: 'bot', text: "Statement_Rahul_Dec2025.pdf", isDoc: true }, { sender: 'bot', text: "Aapka statement ready hai! ✅" }]);
      } else {
        setChatHistory(prev => [...prev, { sender: 'bot', text: `DukaanMitra Assistant: Aapka total pending balance ₹${existingUser?.totalLTV || 0} hai.` }]);
      }
      setIsProcessing(false);
      return;
    }

    // --- DAY 6: BILLING LANE WITH CONFIDENCE LOOP ---
    setActiveRoute("BILLING_LANE");
    setAiRequests(prev => prev + 1);
    const result = await parseMessage(userMsg);

    if (result.intent === 'SKIP') {
      setChatHistory(prev => [...prev, { sender: 'bot', text: "Maaf kijiye, ye bill nahi lag raha. Kripya dhang se likhein." }]);
    } else if (result.confidence <= 0.7) {
      // --- DAY 6: CONFIDENCE FALLBACK ---
      setActiveRoute("FALLBACK_HELP");
      setChatHistory(prev => [...prev, { 
        sender: 'bot', 
        text: "Maaf kijiye 🙏, baat clear nahi hui.\n\nBill ke liye: 'Rahul 500 Chini'\nPayment ke liye: 'Rahul 500 Pay'\n\nKripya dobara likhein." 
      }]);
    } else {
      // Success Path
      const newTrans: Transaction = {
        transId: `uuid-${Date.now()}`,
        storeId: existingUser?.storeId || "DM_DEL_001",
        phone: mockUserPhone,
        customerName: result.customer_name,
        amount: result.intent === 'PAYMENT_RECEIVED' ? -result.amount : result.amount,
        items: result.items,
        date: new Date().toISOString()
      };

      setTransactions(prev => [...prev, newTrans]);
      if (existingUser) {
        setCustomers(prev => prev.map(c => 
          c.phone === mockUserPhone ? { ...c, totalLTV: c.totalLTV + (result.intent === 'PAYMENT_RECEIVED' ? -result.amount : result.amount) } : c
        ));
      }

      setChatHistory(prev => [...prev, { 
        sender: 'bot', 
        text: `Entry Confirm! ✅\nNaam: ${result.customer_name}\nAmount: ₹${result.amount}\nItem: ${result.items}\nType: ${result.intent}` 
      }]);
    }

    setIsProcessing(false);
  };

  const simulateImageBill = async () => {
    setIsProcessing(true);
    setActiveRoute("MEDIA_TRAP");
    setChatHistory(prev => [...prev, { sender: 'user', text: "[PHOTO OF HANDWRITTEN BILL]", isImage: true }]);
    await new Promise(res => setTimeout(res, 1200));
    setChatHistory(prev => [...prev, { sender: 'bot', text: "Sir ji, abhi main photos nahi samajh sakta. Kripya type karke bhejein: 'Aata 200'. 🙂" }]);
    setIsProcessing(false);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 h-[calc(100vh-12rem)]">
      {/* Phone Simulator */}
      <div className="lg:col-span-1 bg-slate-900 rounded-[3rem] p-4 shadow-2xl border-[12px] border-slate-800 relative flex flex-col h-full overflow-hidden">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-32 h-6 bg-slate-800 rounded-b-2xl z-20"></div>

        <div className="flex-1 bg-slate-100 rounded-[2rem] overflow-hidden flex flex-col mt-2">
          <div className="bg-indigo-600 text-white p-4 pt-8 flex items-center justify-between">
            <div className="flex items-center space-x-3">
              <div className="w-10 h-10 bg-indigo-500 rounded-full flex items-center justify-center font-bold">DM</div>
              <div>
                <p className="font-bold text-sm">DukaanMitra Simulator</p>
                <p className="text-[10px] opacity-80">Day 6 Optimization Live</p>
              </div>
            </div>
            <div className="text-right">
              <p className="text-[8px] font-bold opacity-60">COST SAVED</p>
              <p className="text-xs font-black text-emerald-300">₹{costSaved * 2}</p>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-[#e5ddd5]">
            {chatHistory.map((chat, i) => (
              <div key={i} className={`flex ${chat.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-lg text-sm shadow-sm whitespace-pre-wrap ${
                  chat.sender === 'user' 
                    ? 'bg-[#dcf8c6] text-slate-800 rounded-tr-none' 
                    : 'bg-white text-slate-800 rounded-tl-none border-l-4 border-l-indigo-500'
                }`}>
                  {chat.isImage && <div className="w-full h-32 bg-slate-200 rounded mb-2 flex items-center justify-center italic text-xs text-slate-400 border-2 border-dashed border-slate-300">Bill_Image.jpg</div>}
                  {chat.isDoc && (
                    <div className="bg-slate-50 p-3 rounded border border-slate-200 mb-2 flex items-center space-x-3">
                      <span className="text-2xl">📄</span>
                      <div className="flex-1">
                        <p className="text-[10px] font-bold text-slate-900 truncate">{chat.text}</p>
                        <p className="text-[8px] text-slate-400 uppercase font-bold">Download Statement</p>
                      </div>
                    </div>
                  )}
                  {!chat.isDoc && chat.text}
                </div>
              </div>
            ))}
            {isProcessing && (
              <div className="flex justify-start">
                <div className="bg-white text-slate-400 p-2 rounded-lg text-xs animate-pulse">Running Optimization...</div>
              </div>
            )}
            <div ref={chatEndRef} />
          </div>

          <div className="p-3 bg-slate-50 border-t flex items-center space-x-2">
            <button onClick={simulateImageBill} className="text-slate-400 hover:text-indigo-600 transition p-1">📷</button>
            <input 
              type="text" 
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Test 'Ok' or 'Pay 100'..."
              className="flex-1 bg-white border rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
            />
            <button onClick={handleSendMessage} disabled={isProcessing} className="bg-indigo-600 text-white w-10 h-10 rounded-full flex items-center justify-center hover:bg-indigo-700 transition disabled:opacity-50">➔</button>
          </div>
        </div>
      </div>

      {/* Logic Explained Panel */}
      <div className="lg:col-span-2 space-y-6 overflow-y-auto">
        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <h3 className="text-xl font-bold mb-4 flex items-center space-x-2">
            <span className="text-indigo-600">🧠</span>
            <span>Day 6: Optimization Trace</span>
          </h3>
          <div className="space-y-4">
            <div className={`flex items-start space-x-3 p-4 rounded-xl border transition-all duration-300 ${activeRoute === 'CHAI_SUTTA_FILTER' ? 'bg-amber-100 border-amber-500 scale-[1.02]' : 'bg-amber-50 border-amber-100 opacity-60'}`}>
              <div className="bg-amber-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold shrink-0">☕</div>
              <div>
                <p className="font-bold text-slate-900">Chai-Sutta Filter</p>
                <p className="text-sm text-slate-500">Early exit for garbage text. AI call skipped.</p>
              </div>
              {activeRoute === 'CHAI_SUTTA_FILTER' && <span className="ml-auto text-xs font-bold text-amber-600 animate-pulse">MATCHED</span>}
            </div>
            <div className={`flex items-start space-x-3 p-4 rounded-xl border transition-all duration-300 ${activeRoute === 'BILLING_LANE' ? 'bg-emerald-100 border-emerald-500 scale-[1.02]' : 'bg-emerald-50 border-emerald-100 opacity-60'}`}>
              <div className="bg-emerald-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold shrink-0">🤖</div>
              <div>
                <p className="font-bold text-slate-900">AI Intent Engine</p>
                <p className="text-sm text-slate-500">Gemini 3 Flash evaluating financial intent and confidence.</p>
              </div>
              {activeRoute === 'BILLING_LANE' && <span className="ml-auto text-xs font-bold text-emerald-600 animate-pulse">PROCESSING</span>}
            </div>
            <div className={`flex items-start space-x-3 p-4 rounded-xl border transition-all duration-300 ${activeRoute === 'FALLBACK_HELP' ? 'bg-rose-100 border-rose-500 scale-[1.02]' : 'bg-rose-50 border-rose-100 opacity-60'}`}>
              <div className="bg-rose-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold shrink-0">🛡️</div>
              <div>
                <p className="font-bold text-slate-900">Confidence Loop</p>
                <p className="text-sm text-slate-500">Confidence low. Sending dm_clarify template.</p>
              </div>
              {activeRoute === 'FALLBACK_HELP' && <span className="ml-auto text-xs font-bold text-rose-600 animate-pulse">TRIGGERED</span>}
            </div>
          </div>
        </div>

        <div className="bg-slate-900 text-white p-6 rounded-2xl shadow-xl overflow-hidden relative">
          <div className="relative z-10">
             <h3 className="text-xl font-bold mb-4">Cost/Accuracy Ledger</h3>
             <div className="grid grid-cols-2 gap-4 mb-6">
                <div className="bg-white/5 p-4 rounded-xl border border-white/10">
                   <p className="text-[10px] text-slate-400 uppercase font-bold">AI Requests</p>
                   <p className="text-2xl font-black">{aiRequests}</p>
                </div>
                <div className="bg-white/5 p-4 rounded-xl border border-white/10">
                   <p className="text-[10px] text-slate-400 uppercase font-bold">Cost Saved (Units)</p>
                   <p className="text-2xl font-black text-emerald-400">{costSaved}</p>
                </div>
             </div>
             <div className="bg-slate-950 p-4 rounded-lg font-mono text-[10px] h-32 overflow-y-auto">
              <pre className="text-indigo-400">
                {`// SYSTEM OPTIMIZATION TRACE\n`}
                {JSON.stringify({
                  module: "Day6_Cost_Optimizer",
                  pre_filter: costSaved > 0 ? "STRIKETHROUGH_ACTIVE" : "IDLE",
                  ai_temp: 0.1,
                  intent_mapping: "STRICT_JSON",
                  timestamp: new Date().toISOString()
                }, null, 2)}
              </pre>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Simulator;

